const data = $input.first().json.body;
const staticData = $getWorkflowStaticData('global');

if (!staticData.inventario) staticData.inventario = {};
if (!staticData.historial) staticData.historial = [];

const ahora = new Date();
const ahoraStr = ahora.toLocaleString('es-ES', { timeZone: 'Europe/Madrid' });

// Modo consulta: estado actual del inventario
if (data.accion === 'consultar') {
  const equipos = Object.entries(staticData.inventario).map(([equipo, info]) => {
    const resultado = { equipo, ...info };
    if (info.estado === 'prestado' && info.fecha_prestamo_ts) {
      const dias = Math.floor((ahora.getTime() - info.fecha_prestamo_ts) / (1000 * 60 * 60 * 24));
      resultado.dias_prestado = dias;
      if (dias > 7) resultado.alerta = 'Prestamo superior a 7 dias';
    }
    return resultado;
  });
  const prestados = equipos.filter(e => e.estado === 'prestado');
  const disponibles = equipos.filter(e => e.estado === 'disponible');
  const alertas = equipos.filter(e => e.alerta);
  return [{ json: {
    status: 'ok',
    resumen: { total: equipos.length, prestados: prestados.length, disponibles: disponibles.length, alertas: alertas.length },
    equipos,
    alertas: alertas.length > 0 ? alertas : undefined
  } }];
}

if (!data.equipo || !data.accion) {
  return [{ json: { status: 'error', mensaje: 'Campos obligatorios: equipo, accion (prestar/devolver/consultar)' } }];
}

// Prestar equipo
if (data.accion === 'prestar') {
  if (!data.profesor) {
    return [{ json: { status: 'error', mensaje: 'Campo obligatorio para prestamo: profesor' } }];
  }
  const equipo = staticData.inventario[data.equipo];
  if (equipo && equipo.estado === 'prestado') {
    return [{ json: { status: 'error', mensaje: `${data.equipo} ya esta prestado a ${equipo.profesor} desde ${equipo.fecha_prestamo}` } }];
  }
  staticData.inventario[data.equipo] = {
    estado: 'prestado',
    profesor: data.profesor,
    fecha_prestamo: ahoraStr,
    fecha_prestamo_ts: ahora.getTime()
  };
  staticData.historial.push({ equipo: data.equipo, accion: 'prestamo', profesor: data.profesor, fecha: ahoraStr });
  return [{ json: { status: 'ok', mensaje: `${data.equipo} prestado a ${data.profesor}` } }];
}

// Devolver equipo
if (data.accion === 'devolver') {
  const equipo = staticData.inventario[data.equipo];
  if (!equipo || equipo.estado !== 'prestado') {
    return [{ json: { status: 'error', mensaje: `${data.equipo} no esta registrado como prestado` } }];
  }
  const profesor = equipo.profesor;
  staticData.inventario[data.equipo] = {
    estado: 'disponible',
    ultimo_usuario: profesor,
    fecha_devolucion: ahoraStr
  };
  staticData.historial.push({ equipo: data.equipo, accion: 'devolucion', profesor, fecha: ahoraStr });
  return [{ json: { status: 'ok', mensaje: `${data.equipo} devuelto por ${profesor}` } }];
}

return [{ json: { status: 'error', mensaje: 'Accion no valida. Usa: prestar, devolver o consultar' } }];
